  const umsatzMio = umsatzStr !== "" ? parseFloat(umsatzStr) : null;
  const groessenKey = getGroessenKey(umsatzMio);
  const branche = selectedKey ? BENCHMARKS[selectedKey] : null;
  const daten = branche?.groessen[groessenKey] ?? {};
